import{_ as r,o as t,c as a,ag as n}from"./chunks/framework.CvgP6Fyv.js";const f=JSON.parse('{"title":"Factures recurrentes","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/recurring-invoices.md","filePath":"fr/features/recurring-invoices.md"}'),s={name:"fr/features/recurring-invoices.md"};function i(u,e,l,o,c,d){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="factures-recurrentes" tabindex="-1">Factures recurrentes <a class="header-anchor" href="#factures-recurrentes" aria-label="Permalink to &quot;Factures recurrentes&quot;">​</a></h1><p>Automatisez votre facturation reguliere en configurant des factures qui se generent selon un calendrier.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Les factures recurrentes sont des modeles qui creent automatiquement de nouvelles factures a des intervalles definis. Ideal pour :</p><ul><li>Les abonnements mensuels</li><li>La facturation d&#39;abonnements</li><li>L&#39;encaissement des loyers</li><li>Les contrats de maintenance</li><li>Les honoraires de conseil reguliers</li></ul><h2 id="creer-une-facture-recurrente" tabindex="-1">Creer une facture recurrente <a class="header-anchor" href="#creer-une-facture-recurrente" aria-label="Permalink to &quot;Creer une facture recurrente&quot;">​</a></h2><ol><li>Allez dans <strong>Factures recurrentes &gt; Nouveau</strong></li><li>Remplissez le modele : <ul><li><strong>Client</strong> -- A qui facturer</li><li><strong>Lignes de facturation</strong> -- Ce qu&#39;il faut facturer (descriptions, montants, TVA)</li><li><strong>Frequence</strong> -- A quelle frequence (hebdomadaire, mensuelle, trimestrielle, annuelle)</li><li><strong>Date de debut</strong> -- Quand commencer la generation</li></ul></li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><p>La facture recurrente est creee avec le statut <strong>Active</strong> et generera sa premiere facture a la prochaine date programmee.</p><h2 id="options-de-frequence" tabindex="-1">Options de frequence <a class="header-anchor" href="#options-de-frequence" aria-label="Permalink to &quot;Options de frequence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Frequence</th><th>Description</th></tr></thead><tbody><tr><td><strong>Hebdomadaire</strong></td><td>Tous les 7 jours</td></tr><tr><td><strong>Mensuelle</strong></td><td>Le meme jour chaque mois</td></tr><tr><td><strong>Trimestrielle</strong></td><td>Tous les 3 mois</td></tr><tr><td><strong>Annuelle</strong></td><td>Une fois par an</td></tr></tbody></table><h2 id="gerer-les-factures-recurrentes" tabindex="-1">Gerer les factures recurrentes <a class="header-anchor" href="#gerer-les-factures-recurrentes" aria-label="Permalink to &quot;Gerer les factures recurrentes&quot;">​</a></h2><h3 id="mettre-en-pause" tabindex="-1">Mettre en pause <a class="header-anchor" href="#mettre-en-pause" aria-label="Permalink to &quot;Mettre en pause&quot;">​</a></h3><p>Arretez temporairement la generation de factures :</p><ol><li>Ouvrez la facture recurrente</li><li>Cliquez sur <strong>Mettre en pause</strong></li><li>Le statut passe a <strong>En pause</strong> -- aucune facture n&#39;est generee</li></ol><h3 id="reprendre" tabindex="-1">Reprendre <a class="header-anchor" href="#reprendre" aria-label="Permalink to &quot;Reprendre&quot;">​</a></h3><p>Redemarrez une facture recurrente en pause :</p><ol><li>Ouvrez la facture recurrente en pause</li><li>Cliquez sur <strong>Reprendre</strong></li><li>La generation reprend a partir de la prochaine date programmee</li></ol><h3 id="modifier" tabindex="-1">Modifier <a class="header-anchor" href="#modifier" aria-label="Permalink to &quot;Modifier&quot;">​</a></h3><p>La modification d&#39;une facture recurrente n&#39;affecte que les factures <strong>futures</strong>. Les factures deja generees ne sont pas modifiees.</p><h3 id="supprimer" tabindex="-1">Supprimer <a class="header-anchor" href="#supprimer" aria-label="Permalink to &quot;Supprimer&quot;">​</a></h3><p>Supprimez le modele recurrent entierement. Les factures precedemment generees restent dans vos archives.</p><h2 id="factures-generees" tabindex="-1">Factures generees <a class="header-anchor" href="#factures-generees" aria-label="Permalink to &quot;Factures generees&quot;">​</a></h2><p>A chaque declenchement d&#39;une facture recurrente, une nouvelle facture est creee :</p><ul><li>Elle utilise les lignes et le client du modele</li><li>Elle suit votre numerotation de factures actuelle</li><li>Elle commence en tant que <strong>Brouillon</strong> (a examiner et envoyer) ou est envoyee automatiquement si configure</li><li>Chaque facture generee est independante -- vous pouvez la modifier sans affecter le modele</li></ul><h2 id="consulter-l-historique" tabindex="-1">Consulter l&#39;historique <a class="header-anchor" href="#consulter-l-historique" aria-label="Permalink to &quot;Consulter l&#39;historique&quot;">​</a></h2><p>La page de detail de la facture recurrente affiche toutes les factures precedemment generees, vous permettant de suivre l&#39;historique complet de facturation.</p><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><ul><li><strong>Mettre en pause / Reprendre</strong> -- Basculez plusieurs factures recurrentes</li><li><strong>Supprimer</strong> -- Supprimez plusieurs modeles</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Combinez avec les <a href="/fr/features/contracts">contrats</a> pour la facturation contractuelle</li><li>Examinez les factures generees avant le premier envoi automatique pour vous assurer que tout est correct</li><li>Utilisez l&#39;apercu de la prochaine occurrence pour voir quand la prochaine facture sera creee</li><li>Consultez le compteur d&#39;actifs et les indicateurs en haut de la page</li></ul>',30)])])}const m=r(s,[["render",i]]);export{f as __pageData,m as default};
